import React from "react";
import ReactDOM from "react-dom";
import ResumeDocument from "./ResumeDocument";
import { Fade, Zoom } from "react-reveal";

const Resume = (props) => {
	const { showCV, setShowCV } = props;

	return ReactDOM.createPortal(
		<React.Fragment>
			{showCV ? (
				<Zoom top delay={150}>
					<div id="Resume">
						<div className="resumeNav">
							<h1>
								my resume
								<span>&copy;</span>
							</h1>
							<div className="resumeBtn">
								<button
									title="Close"
									onClick={() => {
										setShowCV((CV) => !CV);
									}}
								>
									<svg
										focusable="false"
										viewBox="0 0 24 24"
										aria-hidden="true"
									>
										<path d="M19 6.41L17.59 5 12 10.59 6.41 5 5 6.41 10.59 12 5 17.59 6.41 19 12 13.41 17.59 19 19 17.59 13.41 12z"></path>
									</svg>
								</button>
							</div>
						</div>
						<Fade big duration={750} delay={1000}>
							<ResumeDocument />
						</Fade>
						<div className="resumeNavBtm">
							<h5
								onClick={() => {
									setShowCV((CV) => !CV);
								}}
							>
								Click here to Close
							</h5>
						</div>
					</div>
				</Zoom>
			) : null}
		</React.Fragment>,
		document.getElementById("portals")
	);
};
export default Resume;
